good-example.code-block:
-- src/main/resources/db/migration/V1__expand_order_status_v2.sql ALTER TABLE orders ADD COLUMN status_v2 VARCHAR(40);
UPDATE orders SET status_v2 = CASE status WHEN 'P' THEN 'PENDING' WHEN 'S' THEN 'SHIPPED' WHEN 'C' THEN 'CANCELLED' ELSE 'UNKNOWN' END WHERE status_v2 IS NULL;
-- Later deployable steps: -- 1. Release code that writes both status and status_v2 and reads status_v2 with fallback. -- 2. Verify previous-release data snapshots keep the same business meaning. -- 3. Contract only after rollout: SET NOT NULL on status_v2, then DROP status.

bad-example.code-block:
-- Bad: combines expand, semantic rewrite, and contract in one migration
UPDATE orders SET status = 'PENDING' WHERE status = 'P';
ALTER TABLE orders ADD COLUMN status_v2 VARCHAR(40) NOT NULL DEFAULT 'PENDING';
ALTER TABLE orders DROP COLUMN status;
